const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || "http://localhost:8081";
// Generated by GitHub Copilot
/** Run a benchmark payload and return computed metrics. */
export async function runBenchmark(payload) {
    const response = await fetch(`${API_BASE_URL}/api/v1/benchmarks/run`, {
        method: "POST",
        headers: {
            "Content-Type": "application/json"
        },
        body: JSON.stringify(payload)
    });
    if (!response.ok) {
        const error = await response.json().catch(() => ({ error: "request_failed" }));
        throw new Error(error.message || error.error || "Benchmark run failed");
    }
    return response.json();
}
// Generated by GitHub Copilot
/** Fetch benchmark history summaries for leaderboard-style comparison. */
export async function fetchRuns() {
    const response = await fetch(`${API_BASE_URL}/api/v1/benchmarks/runs`);
    if (!response.ok) {
        throw new Error("Unable to fetch runs");
    }
    const payload = (await response.json());
    return payload.runs;
}
